function exportAllDatatables(){var t=$("#Product-datatable").DataTable(),i=$("#Stock-datatable").DataTable(),r=$("#File-datatable").DataTable(),n;$("#Product-datatable .buttons-print").click();$("#Stock-datatable .buttons-print").click();n=window.open("about:blank","Print View");n.document.write('<html><head><link rel="stylesheet" type="text/css" href="https://cdn.datatables.net/1.11.5/css/jquery.dataTables.min.css"><\/head><body><\/body><\/html>');n.document.close();all=t.table().node().outerHTML;$(n.document.body).append($("#title-print"));$(n.document.body).append($("#barcode"));$(n.document.body).append($("#product-print"));$(n.document.body).append("<html><head><\/head><body>");$(n.document.body).append(document.getElementById("targetTextArea").value.replace(/\n/gi,"<br>"));$(n.document.body).append("<\/body><\/html>");$(n.document.body).append($("#second-print"));$(n.document.body).append(all);all=i.table().node().outerHTML;$(n.document.body).append($('<div style="page-break-after:always"><\/div><div>&nbsp;<\/div>'));$(n.document.body).append($("#third-print"));$(n.document.body).append(all);all=r.table().node().outerHTML;$(n.document.body).append($("<div>&nbsp;<\/div>"));$(n.document.body).append(all);setTimeout(function(){n.print()},500);setTimeout("refreshPage();",600)}function refreshPage(){window.location=location.href}var all="";$(document).ready(function(){var n=$("#add-product-select-id").val()});